// MOCK DE IMGUR PARA DEMO
// Imagem pública de produto similar para simular o upload
// Para a gravação real: faça upload manual em imgur.com e
// substitua a URL abaixo pela URL direta do seu produto
const foto_urls = [
  'https://http2.mlstatic.com/D_NQ_NP_2X_957418-MLB73709416651_122023-E.webp'
];

return [{ json: { ...$json, foto_urls } }];

// Payload fixo para demo do Mini Boneco Darth Vader 3D
// category_id MLB271580 = Figuras de Ação (subcategoria de Brinquedos e Hobbies MLB1132)
// Referência: https://developers.mercadolivre.com.br/pt_br/publicacao-de-produtos
const d = $json;

const payload = {
  title:              d['Nome do produto'],
  category_id:        'MLB271580',
  price:              parseFloat(d['Preço (R$)']),
  currency_id:        'BRL',
  available_quantity: parseInt(d['Quantidade em estoque']),
  buying_mode:        'buy_it_now',
  listing_type_id:    'free',       // free = sem custo, ideal para conta de teste
  condition:          'new',
  description:        d['Descrição'],
  pictures:           d.foto_urls.map(url => ({ source: url })),
  sale_terms: [
    { id: 'WARRANTY_TYPE', value_name: 'Garantia do vendedor' },
    { id: 'WARRANTY_TIME', value_name: '90 dias' }
  ],
  tags: ['immediate_payment'],
  attributes: [
    { id: 'item_condition', value_name: 'Novo' },
    { id: 'BRAND',          value_name: 'Artesanal' },
    { id: 'SELLER_SKU',     value_name: 'DARTH-VADER-3D-001' },
    { id: 'PACKAGE_WEIGHT', value_name: '120 g' },
    { id: 'PACKAGE_LENGTH', value_name: '12 cm' },
    { id: 'PACKAGE_WIDTH',  value_name: '8 cm' },
    { id: 'PACKAGE_HEIGHT', value_name: '15 cm' }
  ],
  shipping: {
    mode:          'me2',
    local_pick_up: false,
    free_shipping: false,
    free_methods:  []
  }
};

return [{ json: { ...d, ml_payload: payload } }];

const r = $json;
const ok = r?.statusCode === 201;

return [{ json: {
  status:       ok ? '✅ Publicado com sucesso!' : `❌ Erro ${r?.statusCode}`,
  item_id:      r?.body?.id        || null,
  link:         r?.body?.permalink || null,
  status_ml:    r?.body?.status    || null,
  erro_detalhe: ok ? null : (r?.body?.message || r?.body?.error || JSON.stringify(r?.body))
}}];
